impl Solution { pub fn remove_comments(black_s: Vec<String>) -> Vec<String> { let (mut black_res, mut black_block, mut black_line) = (vec![], false, String::new()); for s in black_s { let (black_chars, mut i) = (s.as_bytes(), 0); if !black_block { black_line = String::new(); } while i < black_chars.len() { if !black_block && i + 1 < black_chars.len() && black_chars[i] == b'/' && black_chars[i+1] == b'*' { black_block = true; i += 1; } else if black_block && i + 1 < black_chars.len() && black_chars[i] == b'*' && black_chars[i+1] == b'/' { black_block = false; i += 1; } else if !black_block && i + 1 < black_chars.len() && black_chars[i] == b'/' && black_chars[i+1] == b'/' { break; } else if !black_block { black_line.push(black_chars[i] as char); } i += 1; } if !black_block && !black_line.is_empty() { black_res.push(black_line.clone()); } } black_res } }